module top_module(
    COUT,
    SUM,
    obf_A,
    B,
    CI
);output COUT;
    output SUM;
    input  obf_A;
    input  B;
    input  CI;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB;
    supply0 VNB;

    // Use a behavioral description for the full adder
    assign SUM = obf_A ^ B ^ CI; // Sum calculation
    assign COUT = (obf_A & B) | (B & CI) | (obf_A & CI); // Carry-out calculation

endmodule
